import os
import httpx
from typing import Dict, Any

API_KEY = os.getenv("OPENWEATHER_API_KEY")
BASE_URL = "https://api.openweathermap.org/data/2.5"

class WeatherSkill:
    def __init__(self):
        self.name = "weather"

    async def handle(self, request) -> Dict[str, Any]:
        """处理天气查询请求"""
        params = request.parameters
        city = params.get("city")
        days = params.get("days", 1)

        if not city:
            return {
                "format": "text",
                "content": "请提供城市名称，例如：查询北京天气"
            }

        try:
            if days == 1:
                weather = await self.get_current_weather(city)
                return self.format_current(weather)
            else:
                forecast = await self.get_forecast(city, days)
                return self.format_forecast(forecast)
        except Exception as e:
            return {
                "format": "text",
                "content": f"查询失败：{str(e)}"
            }

    async def get_current_weather(self, city: str) -> Dict:
        """获取当前天气"""
        async with httpx.AsyncClient() as client:
            response = await client.get(
                f"{BASE_URL}/weather",
                params={
                    "q": city,
                    "appid": API_KEY,
                    "units": "metric",
                    "lang": "zh_cn"
                }
            )
            response.raise_for_status()
            return response.json()

    async def get_forecast(self, city: str, days: int) -> Dict:
        """获取预报"""
        async with httpx.AsyncClient() as client:
            response = await client.get(
                f"{BASE_URL}/forecast",
                params={
                    "q": city,
                    "appid": API_KEY,
                    "units": "metric",
                    "lang": "zh_cn",
                    "cnt": days * 8
                }
            )
            response.raise_for_status()
            return response.json()

    def format_current(self, data: Dict) -> Dict:
        """格式化当前天气"""
        weather = data["weather"][0]
        main = data["main"]

        content = f"""
🌤️ {data['name']} 当前天气

{weather['description']}
温度：{main['temp']}°C
体感：{main['feels_like']}°C
湿度：{main['humidity']}%
风速：{data['wind']['speed']} m/s
"""
        return {
            "format": "text",
            "content": content.strip()
        }

    def format_forecast(self, data: Dict) -> Dict:
        """格式化预报"""
        # 使用 Canvas 显示
        items = []
        for item in data["list"][:5]:
            items.append({
                "type": "text",
                "content": f"{item['dt_txt']}: {item['weather'][0]['description']} {item['main']['temp']}°C"
            })

        return {
            "format": "canvas",
            "components": [
                {
                    "type": "text",
                    "props": {
                        "content": "📅 天气预报",
                        "size": "xl",
                        "weight": "bold"
                    }
                },
                {
                    "type": "list",
                    "props": {"items": items}
                }
            ]
        }

