def transform_data(data):
    # 聚合
    aggregated = data.groupby('category').agg({
        'value': 'sum',
        'count': 'mean'
    })

    # 透视表
    pivot = data.pivot_table(
        index='date',
        columns='category',
        values='value'
    )

    return aggregated, pivot

