async def rate_limit_middleware(request, next):
    """限流中间件"""
    key = f"rate:{request.user.id}"
    count = await redis.incr(key)
    if count > 100:
        return {"error": "请求过于频繁"}
    await redis.expire(key, 60)
    return await next(request)

